async function callAdvancedRealCaseConfirmedOutcomeActivePackageValidationReport(activeCompilationResult) {
  const compilationPacket = readJson(activeCompilationResult.compilationPath);
  const compiledPackage = readJson(compilationPacket.compiledActiveRulePackagePath);
  const activeRule = compiledPackage.rules.find((rule) => rule.lifecycle === "active");
  if (!activeRule) throw new Error("Missing active confirmed-outcome rule for MCP validation report smoke");
  const expression = activeRule.constraint?.expr || "";
  const expectedControlledOutputSha = expression.match(/controlled_output_sha256\s*==\s*'([^']+)'/)?.[1];
  const expectedLifecycleGateId = expression.match(/lifecycle_gate_id\s*==\s*'([^']+)'/)?.[1];
  if (!expectedControlledOutputSha || !expectedLifecycleGateId) {
    throw new Error(`Could not extract confirmed-outcome expectations for MCP smoke: ${expression}`);
  }
  const artifactPath = writeJson(
    join(repoRoot, ".ta-smoke", "mcp-real-case-confirmed-outcome-active-package-validation-report-artifacts", "valid-confirmed-outcome-artifact.json"),
    {
      artifact_id: "artifact.mcp.confirmed_outcome.valid",
      artifact_type: "confirmed_real_case_outcome",
      schema_version: "0.1",
      units: "n/a",
      created_at: new Date().toISOString(),
      source_refs: activeRule.source?.evidence_refs || ["evidence://mcp/confirmed-outcome"],
      context: {
        teacher_reviewed: true,
        controlled_output_sha256: expectedControlledOutputSha,
        lifecycle_gate_id: expectedLifecycleGateId
      },
      objects: [],
      relations: [],
      topology: { vertices: [], edges: [], faces: [] },
      geometry: { cut_lines: [], fold_lines: [], safe_zones: [] }
    }
  );
  const server = startServer({ TRANSPARENT_AI_APPRENTICE_EXPOSE_ADVANCED_TOOLS: "1" });
  try {
    await server.rpc("initialize", {});
    server.rpc("notifications/initialized", {}).catch(() => {});
    const result = await server.rpc("tools/call", {
      name: "create_real_case_confirmed_outcome_active_package_validation_report",
      arguments: {
        activeCompilation: activeCompilationResult.compilationPath,
        artifact: artifactPath,
        rollbackPoint: compilationPacket.rollbackPoint,
        teacherReviewed: true,
        outputDir: join(repoRoot, ".ta-smoke", "mcp-real-case-confirmed-outcome-active-package-validation-report")
      }
    });
    return JSON.parse(result.content[0].text);
  } finally {
    await server.stop();
  }
}

