function createLocalRagFollowUpQueueSelectionReceiptValidationForMcp(
  handoff,
  outputDirName = "mcp-local-rag-selection-receipt-validation",
  receiptFileName = "mcp-local-rag-selection-receipt.json"
) {
  const template = readJson(handoff.receiptTemplatePath);
  const receipt = JSON.parse(JSON.stringify(template));
  receipt.decision = "teacher_selected_review_only_follow_up";
  const allowedPreferred = [
    "request_more_primary_sources",
    "prepare_disabled_rule_rewrite_review",
    "add_validator_coverage_review",
    "prepare_next_teacher_receipt"
  ];
  const rows = Array.isArray(receipt.itemReviews) ? receipt.itemReviews : [];
  const selectedRow =
    rows.find((row) => (row.allowedFollowUpDecisions || []).includes("request_more_primary_sources")) ||
    rows.find((row) => (row.allowedFollowUpDecisions || []).some((decision) => allowedPreferred.includes(decision)));
  if (!selectedRow) throw new Error("MCP smoke could not find an allowed review-only RAG follow-up lane.");
  const selectedDecision =
    (selectedRow.allowedFollowUpDecisions || []).find((decision) => allowedPreferred.includes(decision)) ||
    "request_more_primary_sources";
  for (const row of rows) {
    if (row.itemId === selectedRow.itemId) {
      row.decision = "select_review_only_follow_up";
      row.selectedFollowUpDecision = selectedDecision;
      row.itemReviewed = true;
      row.noActionBoundaryReviewed = true;
      row.reviewerNote = "MCP smoke selected this review-only RAG follow-up lane.";
      if (row.itemId === "confirm_rollback_retained") row.rollbackStillRetained = true;
    }
    if (row.itemId === "review_primary_source_logic_evidence") {
      row.logicEvidenceReviewed = true;
      row.logicFitDecisionConfirmed = true;
      row.logicEvidenceDecision = "logic_evidence_confirmed";
      row.reviewerNote = row.reviewerNote || "MCP smoke confirmed the primary-source logic evidence.";
    }
  }
  receipt.reviewerNote = "MCP smoke selected exactly one review-only follow-up lane.";
  const receiptPath = writeJson(join(repoRoot, ".ta-smoke", receiptFileName), receipt);
  const result = spawnSync(
    process.execPath,
    [
      join(pluginRoot, "scripts", "knowledge", "validate-rag-follow-up-queue-selection-receipt.mjs"),
      "--follow-up-queue",
      handoff.sourceRagFollowUpQueuePath,
      "--receipt",
      receiptPath,
      "--out-dir",
      join(repoRoot, ".ta-smoke", outputDirName)
    ],
    {
      cwd: repoRoot,
      encoding: "utf8"
    }
  );
  if (result.status !== 0) {
    throw new Error(`Failed to create local RAG follow-up queue selection receipt validation:\n${result.stdout}\n${result.stderr}`);
  }
  return JSON.parse(result.stdout);
}

