function createLocalRagPrimarySourceEvidenceRequestValidationForMcp(
  handoff,
  builderOutputDirName = "mcp-local-rag-primary-source-evidence-request-builder",
  validationOutputDirName = "mcp-local-rag-primary-source-evidence-request-validation",
  sourceFileName = "mcp-primary-source-evidence.json",
  receiptFileName = "mcp-rag-primary-source-evidence-request-receipt.json"
) {
  const builderRun = spawnSync(
    process.execPath,
    [
      join(pluginRoot, "scripts", "knowledge", "create-rag-primary-source-evidence-request-receipt-builder.mjs"),
      "--planning-packet",
      handoff.sourceRagSelectedFollowUpPlanningPacketPath,
      "--out-dir",
      join(repoRoot, ".ta-smoke", builderOutputDirName)
    ],
    {
      cwd: repoRoot,
      encoding: "utf8"
    }
  );
  if (builderRun.status !== 0) {
    throw new Error(`Failed to create local RAG primary-source evidence request builder:\n${builderRun.stdout}\n${builderRun.stderr}`);
  }
  const builderResult = JSON.parse(builderRun.stdout);
  const template = readJson(builderResult.templatePath);
  const sourcePath = writeJson(join(repoRoot, ".ta-smoke", sourceFileName), {
    format: "mcp_primary_source_fixture_v1",
    rule: "When a reviewed source defines a data-to-output relation, preserve its ratio and fixed angle as logic evidence.",
    fields: {
      width: 120,
      flapOffsetRatio: 0.12,
      foldAngleDegrees: 90
    }
  });
  const receiptPath = writeJson(join(repoRoot, ".ta-smoke", receiptFileName), {
    ...template,
    decision: "teacher_provided_primary_sources",
    providedSources: [
      {
        sourceId: "mcp.primary.logic",
        title: "MCP primary source logic fixture",
        uri: sourcePath,
        sourceType: "teacher_note",
        domain: "logic_contract",
        trustLevelAfterReview: "teacher_supplied",
        permissionStatus: "teacher_supplied",
        evidenceReviewed: true,
        reviewOnlyBoundaryReviewed: true,
        logicExtractionHint: "Extract the data-to-output ratio and fixed angle as reusable logic evidence.",
        reviewerNote: "MCP smoke reviewed this local source as evidence only."
      }
    ]
  });
  const validationRun = spawnSync(
    process.execPath,
    [
      join(pluginRoot, "scripts", "knowledge", "validate-rag-primary-source-evidence-request-receipt.mjs"),
      "--planning-packet",
      handoff.sourceRagSelectedFollowUpPlanningPacketPath,
      "--receipt",
      receiptPath,
      "--out-dir",
      join(repoRoot, ".ta-smoke", validationOutputDirName)
    ],
    {
      cwd: repoRoot,
      encoding: "utf8"
    }
  );
  if (validationRun.status !== 0) {
    throw new Error(`Failed to create local RAG primary-source evidence request validation:\n${validationRun.stdout}\n${validationRun.stderr}`);
  }
  return JSON.parse(validationRun.stdout);
}

