function createLocalRagRetrievalDraftReviewValidationForMcp(retrievalDraftRunResult) {
  const fixtureRoot = join(repoRoot, ".ta-smoke", "mcp-local-rag-retrieval-draft-review-validation");
  const builderRun = spawnSync(
    process.execPath,
    [
      join(pluginRoot, "scripts", "knowledge", "create-rag-confirmed-retrieval-draft-review-receipt-builder.mjs"),
      "--retrieval-draft-run",
      retrievalDraftRunResult.runPath,
      "--out-dir",
      join(fixtureRoot, "builder")
    ],
    {
      cwd: repoRoot,
      encoding: "utf8"
    }
  );
  if (builderRun.status !== 0) {
    throw new Error(`Failed to create local RAG retrieval draft review receipt builder:\n${builderRun.stdout}\n${builderRun.stderr}`);
  }
  const builder = JSON.parse(builderRun.stdout);
  const template = readJson(builder.templatePath);
  const receiptPath = writeJson(join(fixtureRoot, "teacher-reviewed-retrieval-draft-review-receipt.json"), {
    ...template,
    decision: "teacher_reviewed_disabled_drafts",
    retrievalReviews: template.retrievalReviews.map((row) =>
      row.rulePath
        ? {
            ...row,
            decision: "approve_disabled_draft_for_rule_dsl_validation",
            evidenceReviewed: true,
            ruleDraftReviewed: true,
            logicExtractionHintReviewed: Boolean(row.logicExtractionHint),
            logicFitDecision: row.logicExtractionHint ? "matches_intended_logic" : "not_applicable",
            reviewerNote: "MCP smoke reviewed this disabled draft and logic hint for review-only Rule DSL validation."
          }
        : row
    )
  });
  const validationRun = spawnSync(
    process.execPath,
    [
      join(pluginRoot, "scripts", "knowledge", "validate-rag-confirmed-retrieval-draft-review-receipt.mjs"),
      "--retrieval-draft-run",
      retrievalDraftRunResult.runPath,
      "--receipt",
      receiptPath,
      "--out-dir",
      join(fixtureRoot, "validation")
    ],
    {
      cwd: repoRoot,
      encoding: "utf8"
    }
  );
  if (validationRun.status !== 0) {
    throw new Error(`Failed to validate local RAG retrieval draft review receipt:\n${validationRun.stdout}\n${validationRun.stderr}`);
  }
  return JSON.parse(validationRun.stdout);
}

