async function callDefaultOriginalGoalFinalCompletionGate() {
  const server = startServer();
  const evidence = writeOriginalGoalFinalCompletionGateEvidence("default-final-completion-gate");
  try {
    await server.rpc("initialize", {});
    server.rpc("notifications/initialized", {}).catch(() => {});
    const result = await server.rpc("tools/call", {
      name: "teach_apprentice",
      arguments: {
        whatToTeach:
          "Run the final completion gate to check whether the original goal can be claimed complete from supplied evidence.",
        validateOriginalGoalFinalCompletionGate: true,
        ...evidence,
        outputDir: join(repoRoot, ".ta-smoke", "mcp-default-final-completion-gate")
      }
    });
    return JSON.parse(result.content[0].text);
  } finally {
    await server.stop();
  }
}

async function callDefaultOriginalGoalCurrentStatusRefresh() {
  const server = startServer();
  const scanRoot = join(repoRoot, ".ta-smoke", "mcp-default-current-status-refresh-empty-scan-root");
  mkdirSync(scanRoot, { recursive: true });
  try {
    await server.rpc("initialize", {});
    server.rpc("notifications/initialized", {}).catch(() => {});
    const result = await server.rpc("tools/call", {
      name: "teach_apprentice",
      arguments: {
        whatToTeach:
          "Refresh the original goal current status and show what the apprentice can safely do next.",
        message:
          "Refresh original goal current status for all-software low-token learning, transparent sketch intent, voice/text control, and supervised execution gates without registering tasks, executing software, or writing memory.",
        originalGoalCurrentStatusRefresh: true,
        software: "ExampleCAD",
        command: "Confirm one numbered target before any execution.",
        scanRoot,
        outputDir: join(repoRoot, ".ta-smoke", "mcp-default-current-status-refresh")
      }
    });
    return JSON.parse(result.content[0].text);
  } finally {
    await server.stop();
  }
}

